operations.insert:
/* Move Data Import / Settings / Instructions from side drawer to top-left sticky drawer */
.side-tab-panel,
body:not(.pallet-view-active) .side-tab-panel {
  position: fixed !important;
  top: 14px !important;
  left: 18px !important;
  right: auto !important;
  bottom: auto !important;
  width: auto !important;
  max-width: none !important;
  height: auto !important;
  min-height: 0 !important;
  padding: 0 !important;
  border: 0 !important;
  border-radius: 0 !important;
  background: transparent !important;
  box-shadow: none !important;
  transform: none !important;
  overflow: visible !important;
  z-index: 1200 !important;
  pointer-events: none !important;
}

.side-tab-panel .tabs,
body:not(.pallet-view-active) .side-tab-panel .tabs {
  position: relative !important;
  top: auto !important;
  right: auto !important;
  left: auto !important;
  bottom: auto !important;
  transform: none !important;
  display: flex !important;
  flex-direction: row !important;
  align-items: center !important;
  justify-content: flex-start !important;
  gap: 8px !important;
  max-height: none !important;
  height: auto !important;
  overflow: visible !important;
  pointer-events: auto !important;
  z-index: 1204 !important;
}

.side-tab-panel .tab-btn,
body:not(.pallet-view-active) .side-tab-panel .tab-btn {
  min-width: 116px !important;
  width: auto !important;
  min-height: 38px !important;
  height: 38px !important;
  padding: 0 15px !important;
  border-radius: 999px !important;
  border: 1px solid #d7e1ec !important;
  background: rgba(255, 255, 255, 0.96) !important;
  color: #34475c !important;
  writing-mode: horizontal-tb !important;
  text-orientation: mixed !important;
  transform: none !important;
  text-align: center !important;
  justify-content: center !important;
  letter-spacing: 0.01em !important;
  font-size: 12.5px !important;
  font-weight: 780 !important;
  box-shadow: 0 10px 28px rgba(8, 20, 34, 0.08) !important;
  opacity: 1 !important;
  pointer-events: auto !important;
}

.side-tab-panel .tab-btn.active,
body:not(.pallet-view-active) .side-tab-panel .tab-btn.active {
  background: #0b5cab !important;
  color: #ffffff !important;
  border-color: #0b5cab !important;
  transform: none !important;
  box-shadow: 0 12px 30px rgba(11, 92, 171, 0.22) !important;
}

.side-tab-panel .tab-btn:not(.active):hover,
body:not(.pallet-view-active) .side-tab-panel .tab-btn:not(.active):hover {
  background: #ffffff !important;
  color: #0b5cab !important;
  border-color: rgba(11, 92, 171, 0.25) !important;
  transform: none !important;
}

.side-tab-panel .tab-panel,
body:not(.pallet-view-active) .side-tab-panel .tab-panel {
  display: none !important;
  margin-top: 10px !important;
  width: min(520px, calc(100vw - 36px)) !important;
  max-height: calc(100vh - 86px) !important;
  overflow-y: auto !important;
  overflow-x: hidden !important;
  padding: 22px !important;
  border-radius: 22px !important;
  background: linear-gradient(180deg, #0f2138 0%, #102b48 62%, #0a182a 100%) !important;
  box-shadow: 0 24px 70px rgba(8, 20, 34, 0.30) !important;
  pointer-events: auto !important;
  animation: topDrawerIn 0.18s ease-out;
}

.side-tab-panel.drawer-open .tab-panel.active,
body:not(.pallet-view-active) .side-tab-panel.drawer-open .tab-panel.active {
  display: block !important;
}

.side-tab-panel.drawer-open,
body:not(.pallet-view-active) .side-tab-panel.drawer-open {
  width: auto !important;
  max-width: none !important;
  height: auto !important;
  padding: 0 !important;
  border-radius: 0 !important;
  background: transparent !important;
  box-shadow: none !important;
  transform: none !important;
  pointer-events: none !important;
}

.side-tab-panel.drawer-closing,
body:not(.pallet-view-active) .side-tab-panel.drawer-closing {
  transform: none !important;
}

body.drawer-active::before {
  background: rgba(8, 20, 34, 0.18) !important;
  backdrop-filter: blur(1px);
}

.side-tab-panel .tab-btn::before,
.side-tab-panel .tab-btn.active::before,
body:not(.pallet-view-active) .side-tab-panel .tab-btn::before,
body:not(.pallet-view-active) .side-tab-panel .tab-btn.active::before {
  display: none !important;
}

@keyframes topDrawerIn {
  from {
    opacity: 0;
    transform: translateY(-8px);
  }
  to {
    opacity: 1;
    transform: translateY(0);
  }
}

@media (max-width: 760px) {
  .side-tab-panel,
  body:not(.pallet-view-active) .side-tab-panel {
    top: 10px !important;
    left: 10px !important;
  }

  .side-tab-panel .tabs,
  body:not(.pallet-view-active) .side-tab-panel .tabs {
    gap: 6px !important;
  }

  .side-tab-panel .tab-btn,
  body:not(.pallet-view-active) .side-tab-panel .tab-btn {
    min-width: 0 !important;
    height: 36px !important;
    padding: 0 10px !important;
    font-size: 11.5px !important;
  }

  .side-tab-panel .tab-panel,
  body:not(.pallet-view-active) .side-tab-panel .tab-panel {
    width: calc(100vw - 20px) !important;
    padding: 18px !important;
  }
}
